#include <iostream>
#include <string>
using namespace std;
class Solution {
public:
	int minSwaps(string s) {
		int n = s.length();
		int count = 0;
		for (int i = 0; i < n; i++) {
			if (s[i] != s[n - i - 1]) {
				count++;
			}
			if (count > n / 2) {
				return -1;
			}
		}
		return count;
	}
};

